actual_<stage>_days = to_days(loan_fcl.timeline_<stage>_date) - to_days(monthly.nextduedate)   -- view FROM bpms.sync_portmonth monthly LEFT JOIN bpms.sync_loan_foreclosure loan_fcl;
var_<stage>_days   = actual_<stage>_days - (Σ target_i for i ≤ stage)   -- cumulative subtraction, not single-stage;
target_total = Σ target_X over all 15 stages; actual_total = Σ actual_X over all 15 stages;
var_total    = Σ (actual_X - target_X) over all 15 stages = actual_total - target_total   -- NOT Σ var_X (var_X is cumulative).
